// Build a numbered context block and a parallel sources list from the
// retrieved Qdrant documents, so citations are deterministic (not left to the LLM).
const items = $input.all();
const seen = new Set();
let context = '';
const sources = [];
let n = 0;
for (const item of items) {
  const d = item.json.document || item.json;
  const text = d.pageContent || d.content || d.text || '';
  const meta = d.metadata || {};
  const url = meta.url || meta.source || meta.sourceURL || 'unknown';
  // De-duplicate by source URL so the same page isn't cited twice.
  if (seen.has(url)) continue;
  seen.add(url);
  n += 1;
  const title = meta.title || url;
  context += `[${n}] ${title} — ${url}\n${text}\n\n`;
  sources.push(`[${n}] ${title} — ${url}`);
}
const question = $('When chat message received').first().json.chatInput;
return [{ json: {
  question,
  context: context || 'No relevant documents were found.',
  sourcesText: sources.join('\n')
} }];

