// Append the deterministic Sources list under the model's answer.
const answer = $json.text || $json.output || $json.response || '';
const sources = $('Build Context').first().json.sourcesText || '';
const out = sources
  ? `${answer}\n\n---\nSources:\n${sources}`
  : answer;
return [{ json: { output: out } }];
